import java.util.*;

public class Main {

    static int N, C, D;
    static int[][][][] dp;
    static int[][] edge;
    static int[] es;
    static int[] gain;

    static int solve(int node, int chef, int day, int st, int up) {
        if (dp[node][chef][day][st] >= 0) return dp[node][chef][day][st];

        int res = 0;

        if (st == es[node]) {
            if (chef > 0 && day > 0 && gain[node] > 0) {
                res += gain[node];
            }
            return dp[node][chef][day][st] = res;
        }

        res = solve(node, chef, day, st + 1, up);

        if (edge[node][st] != up) {
            int nextNode = edge[node][st];

            for (int i = 0; i <= chef; i++) {
                for (int j = 1; j <= day; j++) {
                    int tmp = solve(nextNode, i, j - 1, 0, node)
                            + solve(node, chef - i, day - j, st + 1, up);
                    if (tmp > res) res = tmp;
                }
            }
        }

        return dp[node][chef][day][st] = res;
    }

    static void output(int node, int chef, int day, int st, int up) {
        int res = solve(node, chef, day, st, up);

        if (st == es[node]) {
            if (chef > 0 && day > 0 && gain[node] > 0) {
                System.out.println("build " + (node + 1));
                day--;
            }
            while (day-- > 0) {
                System.out.println("nothing");
            }
            return;
        }

        int tmp = solve(node, chef, day, st + 1, up);
        if (res == tmp) {
            output(node, chef, day, st + 1, up);
            return;
        }

        if (edge[node][st] != up) {
            int nextNode = edge[node][st];

            for (int i = 1; i <= chef; i++) {
                for (int j = 1; j <= day; j++) {
                    tmp = solve(nextNode, i, j - 1, 0, node)
                            + solve(node, chef - i, day - j, st + 1, up);

                    if (tmp == res) {
                        System.out.println("transfer " + (node + 1) + " " + (nextNode + 1) + " " + i);
                        output(nextNode, i, j - 1, 0, node);
                        output(node, chef - i, day - j, st + 1, up);
                        return;
                    }
                }
            }
        }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);

        N = sc.nextInt();
        C = sc.nextInt();
        D = sc.nextInt();

        gain = new int[N];
        for (int i = 0; i < N; i++) {
            gain[i] = sc.nextInt();
        }

        edge = new int[N][N];
        es = new int[N];

        for (int k = 1; k < N; k++) {
            int i = sc.nextInt() - 1;
            int j = sc.nextInt() - 1;

            edge[i][es[i]++] = j;
            edge[j][es[j]++] = i;
        }

        dp = new int[N][C + 1][D + 1][N + 1];

        for (int i = 0; i < N; i++) {
            for (int j = 0; j <= C; j++) {
                for (int k = 0; k <= D; k++) {
                    Arrays.fill(dp[i][j][k], -1);
                }
            }
        }

        int result = solve(0, C, D, 0, -1);
        System.out.println(result);
        output(0, C, D, 0, -1);

        sc.close();
    }
}

